#include <stdio.h>
#include <math.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double x0, y0, z0, x1, y1, z1, x2, y2, z2;
        scanf("%lf %lf %lf", &x0, &y0, &z0);
        scanf("%lf %lf %lf", &x1, &y1, &z1);
        scanf("%lf %lf %lf", &x2, &y2, &z2);

        double sa_x = x1 - x0, sa_y = y1 - y0, sa_z = z1 - z0;
        double sb_x = x2 - x0, sb_y = y2 - y0, sb_z = z2 - z0;

        double sc_x = x0 + sa_y * (z1 - z0) / sqrt(pow(sa_x, 2) + pow(sa_y, 2) + pow(sa_z, 2)) - sa_x * (y1 - y0) / sqrt(pow(sa_x, 2) + pow(sa_y, 2) + pow(sa_z, 2));
        double sc_y = y0 - sa_x * (z1 - z0) / sqrt(pow(sa_x, 2) + pow(sa_y, 2) + pow(sa_z, 2)) - sa_y * (y1 - y0) / sqrt(pow(sa_x, 2) + pow(sa_y, 2) + pow(sa_z, 2));
        double sc_z = z0;

        double sd_x = x0 - sb_y * (z2 - z0) / sqrt(pow(sb_x, 2) + pow(sb_y, 2) + pow(sb_z, 2)) + sb_x * (y2 - y0) / sqrt(pow(sb_x, 2) + pow(sb_y, 2) + pow(sb_z, 2));
        double sd_y = y0 + sb_x * (z2 - z0) / sqrt(pow(sb_x, 2) + pow(sb_y, 2) + pow(sb_z, 2)) - sb_y * (y2 - y0) / sqrt(pow(sb_x, 2) + pow(sb_y, 2) + pow(sb_z, 2));
        double sd_z = z0;

        double gold_x = (sc_x + sd_x) / 2;
        double gold_y = (sc_y + sd_y) / 2;
        double gold_z = (sc_z + sd_z) / 2;

        printf("%.6f %.6f %.6f\n", gold_x, gold_y, gold_z);
    }
    return 0;
}

